import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int bufferSize = 10;

        char[] buffer = new char[bufferSize];

        // Perform boundary check to prevent buffer overflow
        if (input.length() <= bufferSize) {
            input.getChars(0, Math.min(input.length(), bufferSize), buffer, 0);
            System.out.println("Input copied into buffer successfully.");
        } else {
            System.out.println("Input size exceeds buffer size. Please enter a shorter string.");
        }
    }
}

